#include <bits/stdc++.h>
using namespace std;
int n,m,ans;
bool a[1003];
queue<int> nc;
int main(){
    cin>>m>>n;
    for(int i=1;i<=n;i++){
        int w;
        cin>>w;
        if(!a[w])
            nc.push(w),a[w]=1,ans++;
        while(nc.size()>m)
            a[nc.front()]=0,nc.pop();
    }
    cout<<ans;
    return 0;
}
